unit lipdecide;

{$mode objfpc}

interface

uses globals;

function REALCOMPARE(A, B: real): COMPTYPE;
procedure DECIDE;

implementation

uses Math;

function REALCOMPARE(A, B: real): COMPTYPE;
var
  mag, eps, diff: real;
begin
  if (A = 0.0) and (B = 0.0) then
    exit(EQ);

  mag := abs(A);
  if abs(B) > mag then
    mag := abs(B);

  eps := mag * 0.000005; { 5e-6 relative tolerance for 6 significant digits }

  diff := A - B;
  if diff < -eps then
    REALCOMPARE := LT
  else if diff > eps then
    REALCOMPARE := GT
  else
    REALCOMPARE := EQ;
end;

{ Helper: Euclidean distance between two points }
function Dist2(x1, y1, x2, y2: real): real;
begin
  Dist2 := sqrt(sqr(x2 - x1) + sqr(y2 - y1));
end;

{ Helper: area of triangle given three points (signed area * 2, we return abs/2) }
function TriangleArea(x1, y1, x2, y2, x3, y3: real): real;
begin
  TriangleArea := abs(x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) / 2.0;
end;

{ Helper: determine quadrant of a point per spec priority rules }
function Quadrant(px, py: real): integer;
begin
  if (px >= 0) and (py >= 0) then
    Quadrant := 1
  else if (px < 0) and (py >= 0) then
    Quadrant := 2
  else if (px <= 0) and (py < 0) then
    Quadrant := 3
  else
    Quadrant := 4;
end;

{ Helper: check if three points can be contained within or on a circle of given radius }
function FitsInCircle(x1, y1, x2, y2, x3, y3, radius: real): boolean;
var
  d12, d13, d23, maxSide, area, circumR: real;
begin
  d12 := Dist2(x1, y1, x2, y2);
  d13 := Dist2(x1, y1, x3, y3);
  d23 := Dist2(x2, y2, x3, y3);

  { Find the longest side }
  maxSide := d12;
  if d13 > maxSide then maxSide := d13;
  if d23 > maxSide then maxSide := d23;

  area := TriangleArea(x1, y1, x2, y2, x3, y3);

  { If the three points are collinear, the minimum enclosing circle has
    diameter equal to the maximum distance between any two points }
  if REALCOMPARE(area, 0.0) = EQ then
  begin
    { MEC radius = maxSide / 2 }
    FitsInCircle := (REALCOMPARE(maxSide / 2.0, radius) <> GT);
    exit;
  end;

  { Check if the triangle is obtuse or right-angled.
    If the longest side squared >= sum of squares of other two sides,
    then MEC has diameter = longest side. }
  if maxSide = d12 then
  begin
    if REALCOMPARE(sqr(d12), sqr(d13) + sqr(d23)) <> LT then
    begin
      FitsInCircle := (REALCOMPARE(d12 / 2.0, radius) <> GT);
      exit;
    end;
  end
  else if maxSide = d13 then
  begin
    if REALCOMPARE(sqr(d13), sqr(d12) + sqr(d23)) <> LT then
    begin
      FitsInCircle := (REALCOMPARE(d13 / 2.0, radius) <> GT);
      exit;
    end;
  end
  else
  begin
    if REALCOMPARE(sqr(d23), sqr(d12) + sqr(d13)) <> LT then
    begin
      FitsInCircle := (REALCOMPARE(d23 / 2.0, radius) <> GT);
      exit;
    end;
  end;

  { Acute triangle: MEC is the circumscribed circle }
  circumR := (d12 * d13 * d23) / (4.0 * area);
  FitsInCircle := (REALCOMPARE(circumR, radius) <> GT);
end;

{ Helper: compute angle at vertex (x2,y2) formed by points (x1,y1)-(x2,y2)-(x3,y3).
  Returns the angle in radians. Returns -1 if undefined (vertex coincides with endpoint). }
function ComputeAngle(x1, y1, x2, y2, x3, y3: real): real;
var
  dx1, dy1, dx2, dy2, dot, cross, ang: real;
begin
  dx1 := x1 - x2;
  dy1 := y1 - y2;
  dx2 := x3 - x2;
  dy2 := y3 - y2;

  { Check if first or last point coincides with vertex }
  if (REALCOMPARE(dx1, 0.0) = EQ) and (REALCOMPARE(dy1, 0.0) = EQ) then
  begin
    ComputeAngle := -1.0;
    exit;
  end;
  if (REALCOMPARE(dx2, 0.0) = EQ) and (REALCOMPARE(dy2, 0.0) = EQ) then
  begin
    ComputeAngle := -1.0;
    exit;
  end;

  dot := dx1 * dx2 + dy1 * dy2;
  cross := abs(dx1 * dy2 - dy1 * dx2);
  ang := arctan2(cross, dot);
  ComputeAngle := ang;
end;

procedure DECIDE;
var
  i, j, k: integer;
  d, ang: real;
  { LIC 5 }
  quads: array[1..4] of boolean;
  numQuadrants: integer;
  q: integer;
  { LIC 7 }
  lineLen, dx, dy, t, projX, projY, ptDist: real;
  found: boolean;
  { LIC 13 }
  cond1, cond2: boolean;
begin
  { ===== Evaluate CMV (all 15 LICs) ===== }

  { --- LIC 1 --- }
  CMV[1] := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    d := Dist2(X[i], Y[i], X[i+1], Y[i+1]);
    if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
    begin
      CMV[1] := true;
      break;
    end;
  end;

  { --- LIC 2 --- }
  CMV[2] := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    if not FitsInCircle(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2], PARAMETERS.RADIUS1) then
    begin
      CMV[2] := true;
      break;
    end;
  end;

  { --- LIC 3 --- }
  CMV[3] := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    ang := ComputeAngle(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]);
    if REALCOMPARE(ang, 0.0) <> LT then { angle is defined (not -1) }
    begin
      if (REALCOMPARE(ang, PI - PARAMETERS.EPSILON) = LT) or
         (REALCOMPARE(ang, PI + PARAMETERS.EPSILON) = GT) then
      begin
        CMV[3] := true;
        break;
      end;
    end;
  end;

  { --- LIC 4 --- }
  CMV[4] := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    d := TriangleArea(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]);
    if REALCOMPARE(d, PARAMETERS.AREA1) = GT then
    begin
      CMV[4] := true;
      break;
    end;
  end;

  { --- LIC 5 --- }
  CMV[5] := false;
  for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    for q := 1 to 4 do
      quads[q] := false;
    for j := i to i + PARAMETERS.Q_PTS - 1 do
    begin
      q := Quadrant(X[j], Y[j]);
      quads[q] := true;
    end;
    numQuadrants := 0;
    for q := 1 to 4 do
      if quads[q] then
        inc(numQuadrants);
    if numQuadrants > PARAMETERS.QUADS then
    begin
      CMV[5] := true;
      break;
    end;
  end;

  { --- LIC 6 --- }
  CMV[6] := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if REALCOMPARE(X[i+1] - X[i], 0.0) = LT then
    begin
      CMV[6] := true;
      break;
    end;
  end;

  { --- LIC 7 --- }
  CMV[7] := false;
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
    begin
      k := i + PARAMETERS.N_PTS - 1; { last point index }
      dx := X[k] - X[i];
      dy := Y[k] - Y[i];
      lineLen := sqrt(sqr(dx) + sqr(dy));

      found := false;
      for j := i + 1 to k - 1 do
      begin
        if REALCOMPARE(lineLen, 0.0) = EQ then
        begin
          { First and last coincide: distance from that point }
          ptDist := Dist2(X[i], Y[i], X[j], Y[j]);
        end
        else
        begin
          { Project point onto line and compute distance }
          t := ((X[j] - X[i]) * dx + (Y[j] - Y[i]) * dy) / sqr(lineLen);
          projX := X[i] + t * dx;
          projY := Y[i] + t * dy;
          ptDist := Dist2(X[j], Y[j], projX, projY);
        end;
        if REALCOMPARE(ptDist, PARAMETERS.DIST) = GT then
        begin
          found := true;
          break;
        end;
      end;
      if found then
      begin
        CMV[7] := true;
        break;
      end;
    end;
  end;

  { --- LIC 8 --- }
  CMV[8] := false;
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
    begin
      j := i + PARAMETERS.K_PTS + 1;
      d := Dist2(X[i], Y[i], X[j], Y[j]);
      if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then
      begin
        CMV[8] := true;
        break;
      end;
    end;
  end;

  { --- LIC 9 --- }
  CMV[9] := false;
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
    begin
      j := i + PARAMETERS.A_PTS + 1;
      k := j + PARAMETERS.B_PTS + 1;
      if not FitsInCircle(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAMETERS.RADIUS1) then
      begin
        CMV[9] := true;
        break;
      end;
    end;
  end;

  { --- LIC 10 --- }
  CMV[10] := false;
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
    begin
      j := i + PARAMETERS.C_PTS + 1;
      k := j + PARAMETERS.D_PTS + 1;
      ang := ComputeAngle(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
      if REALCOMPARE(ang, 0.0) <> LT then
      begin
        if (REALCOMPARE(ang, PI - PARAMETERS.EPSILON) = LT) or
           (REALCOMPARE(ang, PI + PARAMETERS.EPSILON) = GT) then
        begin
          CMV[10] := true;
          break;
        end;
      end;
    end;
  end;

  { --- LIC 11 --- }
  CMV[11] := false;
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
    begin
      j := i + PARAMETERS.E_PTS + 1;
      k := j + PARAMETERS.F_PTS + 1;
      d := TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
      if REALCOMPARE(d, PARAMETERS.AREA1) = GT then
      begin
        CMV[11] := true;
        break;
      end;
    end;
  end;

  { --- LIC 12 --- }
  CMV[12] := false;
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
    begin
      j := i + PARAMETERS.G_PTS + 1;
      if REALCOMPARE(X[j] - X[i], 0.0) = LT then
      begin
        CMV[12] := true;
        break;
      end;
    end;
  end;

  { --- LIC 13 --- }
  CMV[13] := false;
  if NUMPOINTS >= 3 then
  begin
    cond1 := false;
    cond2 := false;
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
    begin
      j := i + PARAMETERS.K_PTS + 1;
      d := Dist2(X[i], Y[i], X[j], Y[j]);
      if (not cond1) and (REALCOMPARE(d, PARAMETERS.LENGTH1) = GT) then
        cond1 := true;
      if (not cond2) and (REALCOMPARE(d, PARAMETERS.LENGTH2) = LT) then
        cond2 := true;
      if cond1 and cond2 then
        break;
    end;
    CMV[13] := cond1 and cond2;
  end;

  { --- LIC 14 --- }
  CMV[14] := false;
  if NUMPOINTS >= 5 then
  begin
    cond1 := false;
    cond2 := false;
    for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
    begin
      j := i + PARAMETERS.A_PTS + 1;
      k := j + PARAMETERS.B_PTS + 1;
      if (not cond1) and
         (not FitsInCircle(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAMETERS.RADIUS1)) then
        cond1 := true;
      if (not cond2) and
         FitsInCircle(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAMETERS.RADIUS2) then
        cond2 := true;
      if cond1 and cond2 then
        break;
    end;
    CMV[14] := cond1 and cond2;
  end;

  { --- LIC 15 --- }
  CMV[15] := false;
  if NUMPOINTS >= 5 then
  begin
    cond1 := false;
    cond2 := false;
    for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
    begin
      j := i + PARAMETERS.E_PTS + 1;
      k := j + PARAMETERS.F_PTS + 1;
      d := TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
      if (not cond1) and (REALCOMPARE(d, PARAMETERS.AREA1) = GT) then
        cond1 := true;
      if (not cond2) and (REALCOMPARE(d, PARAMETERS.AREA2) = LT) then
        cond2 := true;
      if cond1 and cond2 then
        break;
    end;
    CMV[15] := cond1 and cond2;
  end;

  { ===== Compute PUM from CMV and LCM ===== }
  for i := 1 to 15 do
    for j := 1 to 15 do
    begin
      if i = j then
        { diagonal elements are input; leave unchanged }
      else
      begin
        case LCM[i, j] of
          NOTUSED: PUM[i, j] := true;
          ANDD:    PUM[i, j] := CMV[i] and CMV[j];
          ORR:     PUM[i, j] := CMV[i] or CMV[j];
        end;
      end;
    end;

  { ===== Compute FUV from PUM ===== }
  for i := 1 to 15 do
  begin
    if not PUM[i, i] then
      FUV[i] := true
    else
    begin
      FUV[i] := true;
      for j := 1 to 15 do
      begin
        if not PUM[i, j] then
        begin
          FUV[i] := false;
          break;
        end;
      end;
    end;
  end;

  { ===== Launch decision ===== }
  LAUNCH := true;
  for i := 1 to 15 do
  begin
    if not FUV[i] then
    begin
      LAUNCH := false;
      break;
    end;
  end;
end;

end.
